#init = afterNextRender(() => {
    const view = this.getHostElement().querySelector('ax-wysiwyg-view') as HTMLElement;

    this.zone.runOutsideAngular(async () => {
      if (isBrowser()) {
        const newWysiwyg = new AXWysiwyg();

        await newWysiwyg.init(view, {
          readOnly: true,
        });

        this.wysiwyg.set(newWysiwyg);
      }
    });
  });
